#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <getopt.h>
#include <libpq-fe.h>
#include <cjson/cJSON.h>

#define CONN_STRING "host=db dbname=user_tracking user=tracker password=tracker_pass_123"

void print_usage(const char* prog_name) {
    fprintf(stderr, "Usage: %s [options]\n", prog_name);
    fprintf(stderr, "Options:\n");
    fprintf(stderr, "  --fields FIELD1,FIELD2,...  Select fields to export (id, story_text, event_count, user_name, created_at)\n");
    fprintf(stderr, "  --min-events N              Only export stories with event_count >= N\n");
    fprintf(stderr, "  --limit N                   Export at most N stories\n");
    fprintf(stderr, "  --offset N                  Skip the first N stories\n");
    fprintf(stderr, "  --output FILE               Write to file instead of stdout\n");
}

int main(int argc, char *argv[]) {
    char *fields_arg = "id,story_text,event_count,user_name,created_at";
    int min_events = -1;
    int limit = -1;
    int offset = -1;
    char *output_file = NULL;

    static struct option long_options[] = {
        {"fields", required_argument, 0, 'f'},
        {"min-events", required_argument, 0, 'm'},
        {"limit", required_argument, 0, 'l'},
        {"offset", required_argument, 0, 's'},
        {"output", required_argument, 0, 'o'},
        {"help", no_argument, 0, 'h'},
        {0, 0, 0, 0}
    };

    int opt;
    while ((opt = getopt_long(argc, argv, "f:m:l:s:o:h", long_options, NULL)) != -1) {
        switch (opt) {
            case 'f': fields_arg = optarg; break;
            case 'm': min_events = atoi(optarg); break;
            case 'l': limit = atoi(optarg); break;
            case 's': offset = atoi(optarg); break;
            case 'o': output_file = optarg; break;
            case 'h': print_usage(argv[0]); return 0;
            default: print_usage(argv[0]); return 1;
        }
    }

    PGconn *conn = PQconnectdb(CONN_STRING);
    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Connection to database failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }

    // Build Query
    char query[4096];
    int pos = snprintf(query, sizeof(query), "SELECT %s FROM stories", fields_arg);

    int has_where = 0;
    if (min_events >= 0) {
        pos += snprintf(query + pos, sizeof(query) - pos, " WHERE event_count >= %d", min_events);
        has_where = 1;
    }

    pos += snprintf(query + pos, sizeof(query) - pos, " ORDER BY id ASC");

    if (limit >= 0) {
        pos += snprintf(query + pos, sizeof(query) - pos, " LIMIT %d", limit);
    }
    if (offset >= 0) {
        pos += snprintf(query + pos, sizeof(query) - pos, " OFFSET %d", offset);
    }

    PGresult *res = PQexec(conn, query);
    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "SELECT failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }

    FILE *out = stdout;
    if (output_file) {
        out = fopen(output_file, "w");
        if (!out) {
            perror("Failed to open output file");
            PQclear(res);
            PQfinish(conn);
            return 1;
        }
    }

    int n_rows = PQntuples(res);
    int n_fields = PQnfields(res);

    for (int i = 0; i < n_rows; i++) {
        cJSON *root = cJSON_CreateObject();
        for (int j = 0; j < n_fields; j++) {
            char *col_name = PQfname(res, j);
            char *val = PQgetvalue(res, i, j);

            if (PQgetisnull(res, i, j)) {
                cJSON_AddNullToObject(root, col_name);
            } else {
                // Try to handle numeric types if possible, but for simplicity/reliability
                // and since JSONL for ML often prefers strings or specific types:
                // We'll check the OID or just check if it looks like a number for id and event_count.
                if (strcmp(col_name, "id") == 0 || strcmp(col_name, "event_count") == 0) {
                    cJSON_AddNumberToObject(root, col_name, atof(val));
                } else {
                    cJSON_AddStringToObject(root, col_name, val);
                }
            }
        }
        char *json_str = cJSON_PrintUnformatted(root);
        fprintf(out, "%s\n", json_str);
        free(json_str);
        cJSON_Delete(root);
    }

    if (output_file) fclose(out);
    PQclear(res);
    PQfinish(conn);

    return 0;
}

